func solve(n int64, edges [][]int64, k int64) int64 {
	// Sort edges by weight
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] < edges[j][2]
	})

	// Build adjacency list
	adj := make(map[int64][][2]int64)
	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		adj[u] = append(adj[u], [2]int64{v, w})
		adj[v] = append(adj[v], [2]int64{u, w})
	}

	// Union-Find data structure
	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		rank[i] = 1
	}

	var find func(u int64) int64
	find = func(u int64) int64 {
		if u != parent[u] {
			parent[u] = find(parent[u])
		}
		return parent[u]
	}

	var union func(u, v int64) bool
	union = func(u, v int64) bool {
		uRoot := find(u)
		vRoot := find(v)
		if uRoot == vRoot {
			return false
		}
		if rank[uRoot] < rank[vRoot] {
			parent[uRoot] = vRoot
		} else {
			parent[vRoot] = uRoot
			rank[uRoot] += rank[vRoot]
		}
		return true
	}

	// Kruskal's algorithm to find the minimum maximum cost
	maxCost := int64(0)
	components := n
	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		if union(u, v) {
			components--
			if w > maxCost {
				maxCost = w
			}
			if components == k {
				break
			}
		}
	}

	return maxCost
}
